#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N; scanf("%lld", &N);
        int64_t r = N % 4;
        int64_t x0 = -1;
        for(int64_t f=0; f<28; f+=7){
            if(f % 4 == r){ x0 = f; break; }
        }
        if(x0==-1 || x0 > N){
            printf("-1\n");
        } else {
            int64_t f = x0 + 28 * ((N - x0) / 28);
            printf("%lld\n", f);
        }
    }
    return 0;
}

