import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        r = N % 4
        x0 = -1
        for f in (0,7,14,21):
            if f % 4 == r:
                x0 = f
                break
        if x0 == -1 or x0 > N:
            out.append('-1')
        else:
            f = x0 + 28 * ((N - x0) // 28)
            out.append(str(f))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

